324     if (Sign.isKnownNever(fcPositive | fcNan) || (SignBit && *SignBit))
325       KnownFPClasses &= (fcNegative | fcNan);
326     if (Sign.isKnownNever(fcNegative | fcNan) || (SignBit && !*SignBit))
327       KnownFPClasses &= (fcPositive | fcNan);
328   }
