3498 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3499                                                FPClassTest DemandedMask,
3500                                                KnownFPClass &Known,
3501                                                unsigned Depth) {
3502   Use &U = I->getOperandUse(OpNo);
3503   Value *V = U.get();
3504   Type *VTy = V->getType();
3505 
3506   if (DemandedMask == fcNone) {
3507     if (isa<PoisonValue>(V))
3508       return false;
3509     replaceUse(U, PoisonValue::get(VTy));
3510     return true;
3511   }
3512 
3513   // Handle constant
3514   Instruction *VInst = dyn_cast<Instruction>(V);
3515   if (!VInst) {
3516     // Handle constants and arguments
3517     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3518     Known.knownNot(~DemandedMask);
3519 
3520     if (Known.KnownFPClasses == fcNone) {
3521       if (isa<PoisonValue>(V))
3522         return false;
3523       replaceUse(U, PoisonValue::get(VTy));
3524       return true;
3525     }
3526 
3527     // Do not try to replace values which are already constants (unless we are
3528     // folding to poison). Doing so could promote poison elements to non-poison
3529     // constants.
3530     if (isa<Constant>(V))
3531       return false;
3532 
3533     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3534     if (!FoldedToConst || FoldedToConst == V)
3535       return false;
3536 
3537     replaceUse(U, FoldedToConst);
3538     return true;
3539   }
3540 
3541   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3542     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3543     DemandedMask &= ~NoFPClass;
3544   }
3545 
3546   if (Depth == MaxAnalysisRecursionDepth) {
3547     Known.knownNot(~DemandedMask);
3548     return false;
3549   }
3550 
3551   Value *NewVal;
3552 
3553   if (VInst->hasOneUse()) {
3554     // If the instruction has one use, we can directly simplify it.
3555     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3556   } else {
3557     // If there are multiple uses of this instruction, then we can simplify
3558     // VInst to some other value, but not modify the instruction.
3559     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3560                                                 Depth);
3561   }
3562 
3563   if (!NewVal)
3564     return false;
3565   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3566     salvageDebugInfo(*OpInst);
3567 
3568   replaceUse(U, NewVal);
3569   return true;
