3368   FastMathFlags FMF;
3369   if (auto *FPOp = dyn_cast<FPMathOperator>(I)) {
3370     FMF = FPOp->getFastMathFlags();
3371     DemandedMask = adjustDemandedMaskFromFlags(DemandedMask, FMF);
3372   }
3373 
3374   switch (I->getOpcode()) {
3375   case Instruction::Select: {
3376     // TODO: Can we infer which side it came from based on adjusted result
3377     // class?
3378     KnownFPClass KnownRHS =
3379         computeKnownFPClass(I->getOperand(2), DemandedMask, CxtI, Depth + 1);
3380     if (KnownRHS.isKnownNever(DemandedMask))
3381       return I->getOperand(1);
3382 
3383     KnownFPClass KnownLHS =
3384         computeKnownFPClass(I->getOperand(1), DemandedMask, CxtI, Depth + 1);
3385     if (KnownLHS.isKnownNever(DemandedMask))
3386       return I->getOperand(2);
3387 
3388     adjustKnownFPClassForSelectArm(KnownLHS, I->getOperand(0), I->getOperand(1),
3389                                    /*Invert=*/false, SQ, Depth);
3390     adjustKnownFPClassForSelectArm(KnownRHS, I->getOperand(0), I->getOperand(2),
3391                                    /*Invert=*/true, SQ, Depth);
3392     Known = KnownLHS.intersectWith(KnownRHS);
3393     Known.knownNot(~DemandedMask);
3394     break;
3395   }
3396   case Instruction::FNeg: {
3397     // Special case fneg(fabs(x))
3398     Value *Src;
3399 
3400     Value *FNegSrc = I->getOperand(0);
3401     if (!match(FNegSrc, m_FAbs(m_Value(Src)))) {
3402       Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3403       break;
3404     }
3405 
3406     KnownFPClass KnownSrc =
3407         computeKnownFPClass(Src, fcAllFlags, CxtI, Depth + 1);
3408 
3409     FastMathFlags FabsFMF = cast<FPMathOperator>(FNegSrc)->getFastMathFlags();
3410     FPClassTest ThisDemandedMask =
3411         adjustDemandedMaskFromFlags(DemandedMask, FabsFMF);
3412 
3413     // We cannot apply the NSZ logic with multiple uses. We can apply it if the
3414     // inner fabs has it and this is the only use.
3415     if (Value *Simplified = simplifyDemandedFPClassFnegFabs(
3416             Known, Src, ThisDemandedMask, KnownSrc, /*NSZ=*/false))
3417       return Simplified;
3418     break;
3419   }
3420   case Instruction::Call: {
3421     const CallInst *CI = cast<CallInst>(I);
3422     const Intrinsic::ID IID = CI->getIntrinsicID();
3423     switch (IID) {
3424     case Intrinsic::fabs: {
3425       Value *Src = CI->getArgOperand(0);
3426       KnownFPClass KnownSrc =
3427           computeKnownFPClass(Src, fcAllFlags, CxtI, Depth + 1);
3428 
3429       // NSZ cannot be applied in multiple use case (maybe it could if all uses
3430       // were known nsz)
3431       if (Value *Simplified = simplifyDemandedFPClassFabs(
3432               Known, CI->getArgOperand(0), DemandedMask, KnownSrc,
3433               /*NSZ=*/false))
3434         return Simplified;
3435       break;
3436     }
3437     case Intrinsic::copysign: {
3438       Value *Mag = CI->getArgOperand(0);
3439       Value *Sign = CI->getArgOperand(1);
3440       KnownFPClass KnownMag =
3441           computeKnownFPClass(Mag, fcAllFlags, CxtI, Depth + 1);
3442 
3443       // Rule out some cases by magnitude, which may help prove the sign bit is
3444       // one direction or the other.
3445       KnownMag.knownNot(~llvm::unknown_sign(DemandedMask));
3446 
3447       // Cannot use nsz in the multiple use case.
3448       if (Value *Simplified = simplifyDemandedFPClassCopysignMag(
3449               Mag, DemandedMask, KnownMag, /*NSZ=*/false))
3450         return Simplified;
3451 
3452       KnownFPClass KnownSign =
3453           computeKnownFPClass(Sign, fcAllFlags, CxtI, Depth + 1);
3454 
3455       if (FMF.noInfs())
3456         KnownSign.knownNot(fcInf);
3457       if (FMF.noNaNs())
3458         KnownSign.knownNot(fcNan);
3459 
3460       if (KnownSign.SignBit && KnownMag.SignBit &&
3461           *KnownSign.SignBit == *KnownMag.SignBit)
3462         return Mag;
3463 
3464       Known = KnownFPClass::copysign(KnownMag, KnownSign);
3465       break;
3466     }
3467     case Intrinsic::maximum:
3468     case Intrinsic::minimum:
3469     case Intrinsic::maximumnum:
3470     case Intrinsic::minimumnum: {
3471       KnownFPClass KnownRHS = computeKnownFPClass(
3472           CI->getArgOperand(1), DemandedMask, CxtI, Depth + 1);
3473       if (KnownRHS.isUnknown())
3474         return nullptr;
3475 
3476       KnownFPClass KnownLHS = computeKnownFPClass(
3477           CI->getArgOperand(0), DemandedMask, CxtI, Depth + 1);
3478 
3479       return simplifyDemandedFPClassMinMax(
3480           Known, IID, CI, DemandedMask, KnownLHS, KnownRHS, F,
3481           cast<FPMathOperator>(CI)->hasNoSignedZeros());
3482     }
3483     default:
3484       break;
3485     }
3486 
3487     [[fallthrough]];
3488   }
3489   default:
3490     Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3491     Known.knownNot(~DemandedMask);
3492     break;
3493   }
3494 
3495   return getFPClassConstant(I->getType(), Known.KnownFPClasses);
3496 }
3497 
3498 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3499                                                FPClassTest DemandedMask,
3500                                                KnownFPClass &Known,
3501                                                unsigned Depth) {
3502   Use &U = I->getOperandUse(OpNo);
3503   Value *V = U.get();
3504   Type *VTy = V->getType();
3505 
3506   if (DemandedMask == fcNone) {
3507     if (isa<PoisonValue>(V))
3508       return false;
3509     replaceUse(U, PoisonValue::get(VTy));
3510     return true;
3511   }
3512 
3513   // Handle constant
3514   Instruction *VInst = dyn_cast<Instruction>(V);
3515   if (!VInst) {
3516     // Handle constants and arguments
3517     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3518     Known.knownNot(~DemandedMask);
3519 
3520     if (Known.KnownFPClasses == fcNone) {
3521       if (isa<PoisonValue>(V))
3522         return false;
3523       replaceUse(U, PoisonValue::get(VTy));
3524       return true;
3525     }
3526 
3527     // Do not try to replace values which are already constants (unless we are
3528     // folding to poison). Doing so could promote poison elements to non-poison
3529     // constants.
3530     if (isa<Constant>(V))
3531       return false;
3532 
3533     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3534     if (!FoldedToConst || FoldedToConst == V)
3535       return false;
3536 
3537     replaceUse(U, FoldedToConst);
3538     return true;
3539   }
3540 
3541   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3542     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3543     DemandedMask &= ~NoFPClass;
3544   }
3545 
3546   if (Depth == MaxAnalysisRecursionDepth) {
3547     Known.knownNot(~DemandedMask);
3548     return false;
3549   }
3550 
3551   Value *NewVal;
3552 
3553   if (VInst->hasOneUse()) {
3554     // If the instruction has one use, we can directly simplify it.
3555     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3556   } else {
3557     // If there are multiple uses of this instruction, then we can simplify
3558     // VInst to some other value, but not modify the instruction.
3559     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3560                                                 Depth);
3561   }
3562 
3563   if (!NewVal)
3564     return false;
3565   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3566     salvageDebugInfo(*OpInst);
3567 
3568   replaceUse(U, NewVal);
3569   return true;
3570 }
